// =============================================================================
// CONSTANTS
// =============================================================================

/** Logo fill color - golden yellow */
const LOGO_FILL_COLOR = '#FFD428';

/** Logo background color - dark navy */
const LOGO_BACKGROUND_COLOR = '#242a37';

/** Size mapping in pixels */
const SIZE_MAP = {
  sm: 48,
  md: 64,
  lg: 80,
  xl: 96,
} as const;

/** Icon takes up 65% of container */
const ICON_RATIO = 0.65;

// =============================================================================
// TYPES
// =============================================================================

/**
 * AppLogo Props
 *
 * @acceptance AC-ALG-001: Renders client logo by default
 * @acceptance AC-ALG-002: Renders driver logo when variant="driver"
 * @acceptance AC-ALG-003: Supports 4 sizes (sm, md, lg, xl)
 */
export interface AppLogoProps {
  /** Logo variant - client (scooter) or driver (scooter with driver) */
  variant?: 'driver' | 'client';
  /** Size preset */
  size?: 'sm' | 'md' | 'lg' | 'xl';
  /** Custom style overrides */
  style?: ViewStyle;
  /** Test ID for testing */
  testID?: string;
}

// =============================================================================
// CLIENT LOGO COMPONENT
// =============================================================================

interface LogoSvgProps {
  iconSize: number;
}

const ClientLogoSvg: React.FC<LogoSvgProps> = ({ iconSize }) => (
  <Svg
    width={iconSize}
    height={iconSize}
    viewBox="0 0 65.6658 59.2228"
    preserveAspectRatio="xMidYMid meet"
  >
    <G>
      <Path d={CLIENT_LOGO_PATH} fill={LOGO_FILL_COLOR} />
    </G>
  </Svg>
);

// =============================================================================
// DRIVER LOGO COMPONENT
// =============================================================================

const DriverLogoSvg: React.FC<LogoSvgProps> = ({ iconSize }) => (
  <Svg
    width={iconSize}
    height={iconSize}
    viewBox="0 0 57.9072 65.6308"
    preserveAspectRatio="xMidYMid meet"
  >
    <G>
      <Path d={DRIVER_LOGO_PATHS.main} fill={LOGO_FILL_COLOR} />
      <Path d={DRIVER_LOGO_PATHS.wheel} fill={LOGO_FILL_COLOR} />
      <Path d={DRIVER_LOGO_PATHS.hub} fill={LOGO_FILL_COLOR} />
    </G>
  </Svg>
);

// =============================================================================
// MAIN COMPONENT
// =============================================================================

/**
 * AppLogo Component
 *
 * Displays the Glidey scooter logo with a dark background.
 * Supports both client (scooter side view) and driver (scooter with driver) variants.
 *
 * @example
 * // Default client logo
 * <AppLogo />
 *
 * @example
 * // Driver variant with large size
 * <AppLogo variant="driver" size="lg" />
 */
export const AppLogo: React.FC<AppLogoProps> = ({
  variant = 'client',
  size = 'md',
  style,
  testID = 'app-logo',
}) => {
  const containerSize = SIZE_MAP[size];
  const iconSize = containerSize * ICON_RATIO;

  return (
    <View
      style={[
        styles.container,
        {
          width: containerSize,
          height: containerSize,
        },
        style,
      ]}
      testID={testID}
      accessibilityLabel={
        variant === 'driver' ? 'Glidey Driver logo' : 'Glidey logo'
      }
      accessibilityRole="image"
    >
      {variant === 'driver' ? (
        <DriverLogoSvg iconSize={iconSize} />
      ) : (
        <ClientLogoSvg iconSize={iconSize} />
      )}
    </View>
  );
};

// =============================================================================
// STYLES
// =============================================================================

const styles = StyleSheet.create({
  container: {
    backgroundColor: LOGO_BACKGROUND_COLOR,
    borderRadius: 24,
    alignItems: 'center',
    justifyContent: 'center',
    ...Platform.select({
      ios: {
        shadowColor: '#000',
        shadowOffset: { width: 0, height: 4 },
        shadowOpacity: 0.15,
        shadowRadius: 8,
      },
      android: {
        elevation: 8,
      },
    }),
  },
});

export default AppLogo;
